/**
 * CollegeDetailPage
 */

import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import Navbar from '../components/common/Navbar';
import Spinner from '../components/common/Spinner';
import { collegeAPI } from '../api/services';
import { MapPin, Phone, Globe, Calendar, Award, BookOpen, ArrowLeft, CheckCircle, Building2 } from 'lucide-react';

const TYPE_COLORS = { Government: 'green', 'Government-Aided': 'teal', Private: 'amber', Deemed: 'purple', Central: 'teal' };

export default function CollegeDetailPage() {
  const { id } = useParams();
  const [college, setCollege] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('courses');

  useEffect(() => {
    collegeAPI.getOne(id)
      .then(r => setCollege(r.data.college))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div style={{ display: 'flex', justifyContent: 'center', padding: '4rem 0' }}><Spinner size={40} /></div>
    </div>
  );

  if (!college) return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div style={{ textAlign: 'center', padding: '4rem 2rem' }}>
        <Building2 size={48} color="var(--text-muted)" style={{ marginBottom: '1rem' }} />
        <h2>College not found</h2>
        <Link to="/colleges" className="btn btn-primary" style={{ marginTop: '1rem', display: 'inline-flex' }}>
          <ArrowLeft size={16} /> Back to Colleges
        </Link>
      </div>
    </div>
  );

  const tabs = ['courses', 'facilities', 'admission'];

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <main style={{ padding: '2rem 0' }}>
        <div className="container" style={{ maxWidth: 900 }}>
          <Link to="/colleges" style={{ display: 'inline-flex', alignItems: 'center', gap: '0.4rem', color: 'var(--text-muted)', fontSize: '0.875rem', marginBottom: '1.5rem' }}>
            <ArrowLeft size={14} /> Back to Colleges
          </Link>

          {/* Hero card */}
          <div className="card" style={{ marginBottom: '1.5rem', padding: '2rem' }}>
            <div style={{ display: 'flex', gap: '1.25rem', alignItems: 'flex-start', flexWrap: 'wrap' }}>
              <div style={{
                width: 72, height: 72, borderRadius: 'var(--radius-md)',
                background: 'linear-gradient(135deg, var(--surface-3), var(--navy-600))',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: '1.75rem', fontWeight: 800, color: 'var(--teal-400)',
                border: '2px solid var(--border)', flexShrink: 0,
              }}>
                {college.shortName?.charAt(0) || college.name.charAt(0)}
              </div>

              <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap', marginBottom: '0.5rem' }}>
                  <span className={`badge badge-${TYPE_COLORS[college.type] || 'teal'}`}>{college.type}</span>
                  <span className="badge badge-purple">{college.category}</span>
                  {college.accreditation?.map(a => <span key={a} className="badge badge-amber" style={{ fontSize: '0.7rem' }}>★ {a}</span>)}
                </div>
                <h1 style={{ fontSize: '1.4rem', marginBottom: '0.25rem' }}>{college.name}</h1>
                {college.shortName && <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem', marginBottom: '0.5rem' }}>{college.shortName}</p>}

                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '1.25rem', marginTop: '0.75rem' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                    <MapPin size={14} color="var(--teal-400)" />
                    {college.location.address && `${college.location.address}, `}{college.location.city}, {college.location.state}
                  </div>
                  {college.established && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                      <Calendar size={14} color="var(--amber-400)" />Est. {college.established}
                    </div>
                  )}
                  {college.ranking && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                      <Award size={14} color="var(--green-400)" />{college.ranking}
                    </div>
                  )}
                </div>
              </div>

              {/* Contact */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.4rem', minWidth: 160 }}>
                {college.contact?.phone && (
                  <a href={`tel:${college.contact.phone}`} style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                    <Phone size={13} />{college.contact.phone}
                  </a>
                )}
                {college.contact?.website && (
                  <a href={college.contact.website} target="_blank" rel="noopener noreferrer"
                    style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.8rem', color: 'var(--teal-400)' }}>
                    <Globe size={13} />Visit Website
                  </a>
                )}
              </div>
            </div>

            {college.description && (
              <p style={{ marginTop: '1.25rem', color: 'var(--text-secondary)', fontSize: '0.9rem', lineHeight: 1.7, paddingTop: '1.25rem', borderTop: '1px solid var(--border)' }}>
                {college.description}
              </p>
            )}
          </div>

          {/* Tabs */}
          <div style={{ display: 'flex', gap: '0.25rem', marginBottom: '1.5rem', background: 'var(--surface-1)', padding: '0.25rem', borderRadius: 'var(--radius-md)', border: '1px solid var(--border)' }}>
            {tabs.map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab)} style={{
                flex: 1, padding: '0.55rem', borderRadius: 'var(--radius-sm)', textTransform: 'capitalize',
                background: activeTab === tab ? 'var(--surface-3)' : 'transparent',
                color: activeTab === tab ? 'var(--teal-400)' : 'var(--text-muted)',
                border: `1px solid ${activeTab === tab ? 'var(--border-hover)' : 'transparent'}`,
                cursor: 'pointer', fontSize: '0.875rem', fontWeight: 500, transition: 'var(--transition)',
              }}>{tab}</button>
            ))}
          </div>

          {/* Courses Tab */}
          {activeTab === 'courses' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', animation: 'fadeIn 0.3s ease' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.25rem' }}>
                <BookOpen size={16} color="var(--teal-400)" />
                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1rem' }}>Courses Offered ({college.courses?.length || 0})</h3>
              </div>
              {college.courses?.map((c, i) => (
                <div key={i} className="card" style={{ padding: '1.25rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: '0.5rem' }}>
                    <div>
                      <h4 style={{ fontSize: '0.95rem', marginBottom: '0.25rem' }}>{c.name}</h4>
                      <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                        <span className="badge badge-teal" style={{ fontSize: '0.7rem' }}>{c.degree}</span>
                        {c.duration && <span className="badge" style={{ background: 'var(--surface-3)', color: 'var(--text-muted)', border: '1px solid var(--border)', fontSize: '0.7rem' }}>{c.duration}</span>}
                      </div>
                    </div>
                    <div style={{ textAlign: 'right' }}>
                      {c.fees && <p style={{ fontSize: '0.875rem', fontWeight: 600, color: 'var(--teal-400)' }}>{c.fees}</p>}
                      {c.seats && <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{c.seats} seats</p>}
                    </div>
                  </div>
                  {c.eligibility && (
                    <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginTop: '0.5rem' }}>
                      <span style={{ color: 'var(--text-muted)' }}>Eligibility:</span> {c.eligibility}
                    </p>
                  )}
                </div>
              ))}
            </div>
          )}

          {/* Facilities Tab */}
          {activeTab === 'facilities' && (
            <div className="card" style={{ animation: 'fadeIn 0.3s ease' }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1rem', marginBottom: '1rem' }}>Campus Facilities</h3>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '0.65rem' }}>
                {college.facilities?.length > 0 ? college.facilities.map(f => (
                  <div key={f} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                    <CheckCircle size={15} color="var(--green-400)" />{f}
                  </div>
                )) : <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>No facilities listed.</p>}
              </div>
              {college.affiliation && (
                <div style={{ marginTop: '1.5rem', paddingTop: '1.25rem', borderTop: '1px solid var(--border)' }}>
                  <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Affiliated to</p>
                  <p style={{ fontWeight: 600, color: 'var(--text-primary)' }}>{college.affiliation}</p>
                </div>
              )}
            </div>
          )}

          {/* Admission Tab */}
          {activeTab === 'admission' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem', animation: 'fadeIn 0.3s ease' }}>
              <div className="card">
                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1rem', marginBottom: '1rem' }}>Admission Process</h3>
                {college.admission?.process && <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', lineHeight: 1.7, marginBottom: '1.25rem' }}>{college.admission.process}</p>}

                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '1rem' }}>
                  {college.admission?.entranceExams?.length > 0 && (
                    <div>
                      <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '0.5rem' }}>Entrance Exams</p>
                      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.4rem' }}>
                        {college.admission.entranceExams.map(e => <span key={e} className="badge badge-purple" style={{ fontSize: '0.75rem' }}>{e}</span>)}
                      </div>
                    </div>
                  )}
                  <div>
                    <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '0.5rem' }}>Application Period</p>
                    {college.admission?.applicationStart && (
                      <p style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                        {college.admission.applicationStart} – {college.admission.applicationEnd || 'TBA'}
                      </p>
                    )}
                  </div>
                </div>

                {college.admission?.website && (
                  <a href={college.admission.website} target="_blank" rel="noopener noreferrer" className="btn btn-primary btn-sm" style={{ marginTop: '1rem', display: 'inline-flex' }}>
                    Apply / Official Website
                  </a>
                )}
              </div>

              {/* Document Checklist */}
              <div className="card">
                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1rem', marginBottom: '1rem' }}>📋 Document Checklist</h3>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
                  {['10th Mark Sheet & Certificate', '12th Mark Sheet & Certificate', 'Transfer Certificate (TC)', 'Conduct Certificate', 'Community / Caste Certificate (if applicable)', 'Income Certificate (for scholarship)', 'Aadhar Card / ID Proof', '4 Passport Size Photographs', 'Migration Certificate (for CBSE/ICSE)', 'Entrance Exam Scorecard (if applicable)'].map(doc => (
                    <div key={doc} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                      <div style={{ width: 18, height: 18, border: '2px solid var(--border)', borderRadius: 4, flexShrink: 0 }} />
                      {doc}
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
